const amqp = require('amqplib');
const { exec } = require('child_process');
const mysql = require('mysql');

const RABBITMQ_URL = 'amqp://localhost';
const QUEUE_NAME = 'task_queue';

const db = mysql.createConnection({
  host: 'localhost',
  user: 'root',
  password: 'password',
  database: 'mydb'
});

async function start() {
  try {
    const connection = await amqp.connect(RABBITMQ_URL);
    const channel = await connection.createChannel();
    await channel.assertQueue(QUEUE_NAME, { durable: true });

    console.log(`Waiting for messages in ${QUEUE_NAME}. To exit press CTRL+C`);

    channel.consume(QUEUE_NAME, async (msg) => {
      if (msg !== null) {
        try {
          const messageContent = msg.content.toString();
          const message = JSON.parse(messageContent);

          if (typeof message !== 'object' || !message.type || !message.payload) {
            throw new Error('Invalid message format');
          }

          switch (message.type) {
            case 'database_query':
              handleDatabaseQuery(message.payload);
              break;
            case 'system_command':
              handleSystemCommand(message.payload);
              break;
            default:
              console.log('Unknown message type');
          }
        } catch (error) {
          console.error('Error processing message:', error.message);
        } finally {
          channel.ack(msg);
        }
      }
    });
  } catch (error) {
    console.error('Error connecting to RabbitMQ:', error.message);
  }
}

function handleDatabaseQuery(payload) {
  if (!payload.query || typeof payload.query !== 'string') {
    console.error('Invalid database query payload');
    return;
  }

  db.query(payload.query, (error, results) => {
    if (error) {
      console.error('Database query error:', error.message);
    } else {
      console.log('Database query results:', results);
    }
  });
}

function handleSystemCommand(payload) {
  if (!payload.command || typeof payload.command !== 'string') {
    console.error('Invalid system command payload');
    return;
  }

  exec(payload.command, (error, stdout, stderr) => {
    if (error) {
      console.error('System command error:', error.message);
    } else {
      console.log('System command output:', stdout);
      if (stderr) {
        console.error('System command stderr:', stderr);
      }
    }
  });
}

start();